.demo {
  font-family: "Trebuchet MS", "Segoe UI", sans-serif;
  border: 2px solid #1d3d2f;
  border-radius: 14px;
  max-width: 380px;
  margin: 1rem auto;
  padding: 1.2rem;
  background: linear-gradient(145deg, #f4f8f2, #e4efe7);
  color: #183026;
}

.demo h1 {
  margin-top: 0;
  font-size: 1.25rem;
}

.actions {
  display: flex;
  gap: 0.6rem;
}

.actions button {
  border: 0;
  border-radius: 8px;
  background: #29543f;
  color: #fff;
  font-weight: 700;
  padding: 0.55rem 0.85rem;
  cursor: pointer;
}

#status[data-state="positive"] strong {
  color: #0a7a3e;
}

#status[data-state="negative"] strong {
  color: #a12622;
}
